import{_ as a,o as d,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"工商业储能投资 IRR 与 2026 年峰谷价差趋势","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"电力新能源/储能/_深化_2026-06-16_工商业储能IRR与峰谷价差.md","filePath":"电力新能源/储能/_深化_2026-06-16_工商业储能IRR与峰谷价差.md","lastUpdated":null}'),l={name:"电力新能源/储能/_深化_2026-06-16_工商业储能IRR与峰谷价差.md"};function i(o,t,h,n,s,u){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="工商业储能投资-irr-与-2026-年峰谷价差趋势" tabindex="-1">工商业储能投资 IRR 与 2026 年峰谷价差趋势 <a class="header-anchor" href="#工商业储能投资-irr-与-2026-年峰谷价差趋势" aria-label="Permalink to &quot;工商业储能投资 IRR 与 2026 年峰谷价差趋势&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>2026 年工商业储能 IRR 全国普遍在 8%-15%，广东/东莞地区因高峰谷价差可达 12%-18%。关键变化是：9 省市已取消行政分时电价，转向市场分时定价，峰谷价差普遍收窄（江苏降 28%）。单一峰谷套利模式终结，多元收益（容需管理+能量时移+辅助服务）成为新核心，可将 IRR 从 6.2% 拉回 18.5%。</p><h2 id="irr-全景" tabindex="-1">IRR 全景 <a class="header-anchor" href="#irr-全景" aria-label="Permalink to &quot;IRR 全景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>区域</th><th>IRR 区间</th><th>静态回收期</th><th>关键条件</th></tr></thead><tbody><tr><td>全国普通地区</td><td>6%-10%</td><td>6-10 年</td><td>峰谷差 &lt;0.5 元/kWh</td></tr><tr><td>电价较好地区</td><td>10%-15%</td><td>5-7 年</td><td>峰谷差 0.6-0.7 元/kWh</td></tr><tr><td>广东/东莞</td><td>12%-18%</td><td>4-6 年</td><td>峰谷差 &gt;0.7 元/kWh</td></tr><tr><td>优质项目（24h 生产+补贴）</td><td>18%-22%</td><td>3.5-4 年</td><td>补贴 + 高利用率</td></tr></tbody></table><h3 id="广东最优案例" tabindex="-1">广东最优案例 <a class="header-anchor" href="#广东最优案例" aria-label="Permalink to &quot;广东最优案例&quot;">​</a></h3><ul><li><strong>储能成本</strong>：2026 年 4 月广东储能系统中标价 0.973 元/Wh（深南电中山项目），较 2022 年高峰跌超 50%</li><li><strong>峰谷价差</strong>：珠三角五市最大峰谷价差 1.1577 元/kWh，全国第一</li><li><strong>两充两放 IRR</strong>：14%-18%（一充一放仅 6%-8%）</li><li><strong>同一套设备</strong>：保守策略（年净收益 10.4 万）vs 最优策略（25.3 万），差距 14.9 万/年</li></ul><h2 id="政策变革-取消行政分时电价" tabindex="-1">政策变革：取消行政分时电价 <a class="header-anchor" href="#政策变革-取消行政分时电价" aria-label="Permalink to &quot;政策变革：取消行政分时电价&quot;">​</a></h2><h3 id="依据文件" tabindex="-1">依据文件 <a class="header-anchor" href="#依据文件" aria-label="Permalink to &quot;依据文件&quot;">​</a></h3><p>国家发改委/能源局《电力中长期市场基本规则》（发改能源规〔2025〕1656 号），2025 年 12 月发布，自 2026 年 3 月 1 日起实施。明确：&quot;直接参与市场交易的经营主体，不再人为规定分时电价水平和时段。&quot;</p><h3 id="落地情况" tabindex="-1">落地情况 <a class="header-anchor" href="#落地情况" aria-label="Permalink to &quot;落地情况&quot;">​</a></h3><p>截至 2026 年 2 月，11 省市发布相关通知，9 省市已明确落地取消：</p><ul><li><strong>已明确取消（9 地）</strong>：贵州、河北（南网）、湖北、陕西、吉林、云南、重庆、辽宁、河南</li><li><strong>征求意见阶段（2 地）</strong>：江苏、山西</li><li><strong>调整未取消</strong>：浙江等调整政策但保留框架</li></ul><h3 id="对工商业储能的影响" tabindex="-1">对工商业储能的影响 <a class="header-anchor" href="#对工商业储能的影响" aria-label="Permalink to &quot;对工商业储能的影响&quot;">​</a></h3><ol><li><strong>短期阵痛</strong>：多地峰谷价差收窄，江苏从 0.85 降至 0.62 元/kWh（降 28%），IRR 从约 10% 降至 6%</li><li><strong>资本撤离</strong>：部分投资方因收益率无法确定，正在撤离工商储赛道</li><li><strong>长期利好</strong>：市场化定价激发活力，储售一体化运营可增收 15%-20%</li></ol><h2 id="多元收益模式" tabindex="-1">多元收益模式 <a class="header-anchor" href="#多元收益模式" aria-label="Permalink to &quot;多元收益模式&quot;">​</a></h2><p>在新的市场分时电价下，单靠峰谷套利已不可行，多元收益成为生存关键：</p><table tabindex="0"><thead><tr><th>收益来源</th><th>占比</th><th>说明</th></tr></thead><tbody><tr><td>峰谷套利</td><td>40%-50%</td><td>仍是最主要来源，但占比下降</td></tr><tr><td>容需管理（需量费管控）</td><td>15%-25%</td><td>每降低 100kW 需量，年省 5-6 万元</td></tr><tr><td>能量时移</td><td>10%-15%</td><td>光伏余电存储，高峰自用</td></tr><tr><td>辅助服务</td><td>10%-15%</td><td>调频/调峰/备用</td></tr><tr><td>地方补贴</td><td>5%-10%</td><td>广东+东莞可提升 IRR 3-5pct</td></tr></tbody></table><h3 id="实用案例-江苏" tabindex="-1">实用案例（江苏） <a class="header-anchor" href="#实用案例-江苏" aria-label="Permalink to &quot;实用案例（江苏）&quot;">​</a></h3><p>根据远景能源&quot;远景公式&quot;：</p><ul><li>新政后仅峰谷套利：IRR 6.2%（红区）</li><li>峰谷套利+容需管理+能量时移：IRR 18.5%（绿区），回本期 &lt;5 年</li></ul><h3 id="核心公式" tabindex="-1">核心公式 <a class="header-anchor" href="#核心公式" aria-label="Permalink to &quot;核心公式&quot;">​</a></h3><p>光大证券测算量化关系：</p><ul><li>现货价差 +0.01 元/kWh → IRR +1.4pct</li><li>每日满充放次数 +0.1 → IRR +4.4pct</li></ul><h2 id="各省-ir-测算-光大证券" tabindex="-1">各省 IR 测算（光大证券） <a class="header-anchor" href="#各省-ir-测算-光大证券" aria-label="Permalink to &quot;各省 IR 测算（光大证券）&quot;">​</a></h2><p>在 2025 年全年现货市场持续运行的地区中：</p><table tabindex="0"><thead><tr><th>省份</th><th>资本金 IRR</th><th>特征</th></tr></thead><tbody><tr><td>山西</td><td>&gt;6.5%</td><td>现货价差扩大</td></tr><tr><td>内蒙古</td><td>&gt;6.5%</td><td>新能源大发</td></tr><tr><td>山东</td><td>&gt;6.5%</td><td>时段性供需错配</td></tr><tr><td>甘肃</td><td>&gt;6.5%</td><td>现货价差扩大</td></tr><tr><td>广东</td><td>&gt;8%</td><td>高电价+高差</td></tr><tr><td>江苏</td><td>5%-6%</td><td>价差收窄影响</td></tr></tbody></table><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>2026 年是工商业储能的&quot;分水岭年&quot;。行政分时电价的取消淘汰了一批依赖单一套利的参与者，但也催生了真正具备运营能力的玩家。核心能力从&quot;选址拿项目&quot;转向&quot;智能调度+多元收益优化&quot;。广东仍是最优市场，多元收益模式是生存必需。</p><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li>市场分时电价规则尚未完全明确，收益率不确定性高</li><li>各省政策节奏不一，跨省投资需要差异化策略</li><li>储能系统价格继续下行可能压缩设备商利润</li><li>辅助服务市场规则仍在完善中</li></ol><hr><p><em>来源：经济观察网、国家能源局、光大证券研报、远景能源、索比光伏网</em><em>更新：2026-06-16</em></p>',33)])])}const _=a(l,[["render",i]]);export{c as __pageData,_ as default};
